def assess(record: dict) -> str:
    required = {"case_id", 'slice_n', 'precision', 'min_n'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if record["slice_n"] < record["min_n"] else "REJECT_LOW_N_CLAIM"

